module top_module(
    input clk,
    input reset,
    output reg [1:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to zero
            q <= 2'b00;
        end else begin
            // Johnson counter: Rotate the bits and complement the new bit
            q <= {q[0], ~q[1]};
        end
    end

endmodule
